package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFoundException
import com.maum.backend.exception.NotFollowingException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {

    /**
     * 팔로우 처리
     * @param followerId 팔로우를 하는 사용자 ID
     * @param followeeId 팔로우를 받는 사용자 ID
     */
    @Transactional
    fun follow(followerId: String, followeeId: String): FollowEntity {
        // 자기 자신 팔로우 방지
        if (followerId == followeeId) {
            throw SelfFollowException("자기 자신을 팔로우할 수 없습니다.")
        }

        // 팔로워 존재 확인
        userRepository.findById(followerId)
            .orElseThrow { NotFoundException("팔로워 사용자를 찾을 수 없습니다: $followerId") }

        // 팔로이 존재 확인
        userRepository.findById(followeeId)
            .orElseThrow { NotFoundException("팔로우 대상 사용자를 찾을 수 없습니다: $followeeId") }

        // 이미 팔로우 중인지 확인
        if (followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw AlreadyFollowingException("이미 팔로우 중인 사용자입니다.")
        }

        val follow = FollowEntity(
            followerId = followerId,
            followeeId = followeeId,
        )
        return followRepository.save(follow)
    }

    /**
     * 언팔로우 처리
     * @param followerId 언팔로우를 하는 사용자 ID
     * @param followeeId 언팔로우 대상 사용자 ID
     */
    @Transactional
    fun unfollow(followerId: String, followeeId: String) {
        // 자기 자신 언팔로우 방지
        if (followerId == followeeId) {
            throw SelfFollowException("자기 자신을 언팔로우할 수 없습니다.")
        }

        // 팔로우 관계 존재 확인
        if (!followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw NotFollowingException("팔로우 중이 아닌 사용자입니다.")
        }

        followRepository.deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    /**
     * 팔로우 여부 확인
     */
    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followeeId: String): Boolean {
        return followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    /**
     * 팔로워 수 조회
     */
    @Transactional(readOnly = true)
    fun getFollowerCount(userId: String): Long {
        userRepository.findById(userId)
            .orElseThrow { NotFoundException("사용자를 찾을 수 없습니다: $userId") }
        return followRepository.countByFolloweeId(userId)
    }

    /**
     * 팔로잉 수 조회
     */
    @Transactional(readOnly = true)
    fun getFollowingCount(userId: String): Long {
        userRepository.findById(userId)
            .orElseThrow { NotFoundException("사용자를 찾을 수 없습니다: $userId") }
        return followRepository.countByFollowerId(userId)
    }
}

package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFoundException
import com.maum.backend.exception.NotFollowingException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.Mockito.`when`
import org.mockito.junit.jupiter.MockitoExtension
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ─────────────────────────────────────────────
    // follow()
    // ─────────────────────────────────────────────

    @Test
    fun `should follow successfully when both users exist and not yet following`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val follower = UserEntity(id = followerId, nickname = "Alice")
        val followee = UserEntity(id = followeeId, nickname = "Bob")
        val savedFollow = FollowEntity(id = "follow-1", followerId = followerId, followeeId = followeeId)

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(follower))
        `when`(userRepository.findById(followeeId)).thenReturn(Optional.of(followee))
        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(false)
        `when`(followRepository.save(org.mockito.kotlin.any())).thenReturn(savedFollow)

        // when
        val result = userService.follow(followerId, followeeId)

        // then
        assertThat(result.followerId).isEqualTo(followerId)
        assertThat(result.followeeId).isEqualTo(followeeId)
        verify(followRepository).save(org.mockito.kotlin.any())
    }

    @Test
    fun `should throw SelfFollowException when follower and followee are the same`() {
        // given
        val userId = "user-A"

        // when & then
        assertThrows<SelfFollowException> {
            userService.follow(userId, userId)
        }

        // 자기 자신 팔로우 시 DB 조회가 발생하지 않아야 한다
        verify(userRepository, never()).findById(org.mockito.kotlin.any())
        verify(followRepository, never()).save(org.mockito.kotlin.any())
    }

    @Test
    fun `should throw NotFoundException when follower does not exist`() {
        // given
        val followerId = "non-existent-follower"
        val followeeId = "user-B"

        `when`(userRepository.findById(followerId)).thenReturn(Optional.empty())

        // when & then
        val exception = assertThrows<NotFoundException> {
            userService.follow(followerId, followeeId)
        }

        assertThat(exception.message).contains(followerId)
        verify(followRepository, never()).save(org.mockito.kotlin.any())
    }

    @Test
    fun `should throw NotFoundException when followee does not exist`() {
        // given
        val followerId = "user-A"
        val followeeId = "non-existent-followee"
        val follower = UserEntity(id = followerId, nickname = "Alice")

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(follower))
        `when`(userRepository.findById(followeeId)).thenReturn(Optional.empty())

        // when & then
        val exception = assertThrows<NotFoundException> {
            userService.follow(followerId, followeeId)
        }

        assertThat(exception.message).contains(followeeId)
        verify(followRepository, never()).save(org.mockito.kotlin.any())
    }

    @Test
    fun `should throw AlreadyFollowingException when already following`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val follower = UserEntity(id = followerId, nickname = "Alice")
        val followee = UserEntity(id = followeeId, nickname = "Bob")

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(follower))
        `when`(userRepository.findById(followeeId)).thenReturn(Optional.of(followee))
        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(true)

        // when & then
        assertThrows<AlreadyFollowingException> {
            userService.follow(followerId, followeeId)
        }

        verify(followRepository, never()).save(org.mockito.kotlin.any())
    }

    // ─────────────────────────────────────────────
    // unfollow()
    // ─────────────────────────────────────────────

    @Test
    fun `should unfollow successfully when follow relationship exists`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"

        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(true)

        // when
        userService.unfollow(followerId, followeeId)

        // then
        verify(followRepository).deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Test
    fun `should throw SelfFollowException when trying to unfollow self`() {
        // given
        val userId = "user-A"

        // when & then
        assertThrows<SelfFollowException> {
            userService.unfollow(userId, userId)
        }

        verify(followRepository, never()).deleteByFollowerIdAndFolloweeId(org.mockito.kotlin.any(), org.mockito.kotlin.any())
    }

    @Test
    fun `should throw NotFollowingException when follow relationship does not exist`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"

        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(false)

        // when & then
        assertThrows<NotFollowingException> {
            userService.unfollow(followerId, followeeId)
        }

        verify(followRepository, never()).deleteByFollowerIdAndFolloweeId(org.mockito.kotlin.any(), org.mockito.kotlin.any())
    }

    // ─────────────────────────────────────────────
    // isFollowing()
    // ─────────────────────────────────────────────

    @Test
    fun `should return true when following`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"

        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(true)

        // when
        val result = userService.isFollowing(followerId, followeeId)

        // then
        assertThat(result).isTrue()
    }

    @Test
    fun `should return false when not following`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"

        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)).thenReturn(false)

        // when
        val result = userService.isFollowing(followerId, followeeId)

        // then
        assertThat(result).isFalse()
    }

    // ─────────────────────────────────────────────
    // getFollowerCount()
    // ─────────────────────────────────────────────

    @Test
    fun `should return follower count when user exists`() {
        // given
        val userId = "user-B"
        val user = UserEntity(id = userId, nickname = "Bob")

        `when`(userRepository.findById(userId)).thenReturn(Optional.of(user))
        `when`(followRepository.countByFolloweeId(userId)).thenReturn(42L)

        // when
        val count = userService.getFollowerCount(userId)

        // then
        assertThat(count).isEqualTo(42L)
    }

    @Test
    fun `should return zero follower count when user has no followers`() {
        // given
        val userId = "user-new"
        val user = UserEntity(id = userId, nickname = "Newbie")

        `when`(userRepository.findById(userId)).thenReturn(Optional.of(user))
        `when`(followRepository.countByFolloweeId(userId)).thenReturn(0L)

        // when
        val count = userService.getFollowerCount(userId)

        // then
        assertThat(count).isZero()
    }

    @Test
    fun `should throw NotFoundException when getting follower count for non-existent user`() {
        // given
        val userId = "ghost-user"

        `when`(userRepository.findById(userId)).thenReturn(Optional.empty())

        // when & then
        val exception = assertThrows<NotFoundException> {
            userService.getFollowerCount(userId)
        }

        assertThat(exception.message).contains(userId)
        verify(followRepository, never()).countByFolloweeId(org.mockito.kotlin.any())
    }

    // ─────────────────────────────────────────────
    // getFollowingCount()
    // ─────────────────────────────────────────────

    @Test
    fun `should return following count when user exists`() {
        // given
        val userId = "user-A"
        val user = UserEntity(id = userId, nickname = "Alice")

        `when`(userRepository.findById(userId)).thenReturn(Optional.of(user))
        `when`(followRepository.countByFollowerId(userId)).thenReturn(10L)

        // when
        val count = userService.getFollowingCount(userId)

        // then
        assertThat(count).isEqualTo(10L)
    }

    @Test
    fun `should throw NotFoundException when getting following count for non-existent user`() {
        // given
        val userId = "ghost-user"

        `when`(userRepository.findById(userId)).thenReturn(Optional.empty())

        // when & then
        val exception = assertThrows<NotFoundException> {
            userService.getFollowingCount(userId)
        }

        assertThat(exception.message).contains(userId)
        verify(followRepository, never()).countByFollowerId(org.mockito.kotlin.any())
    }
}

