package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFoundException
import com.maum.backend.exception.NotFollowingException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {

    @Transactional
    fun follow(followerId: String, followeeId: String): FollowEntity {
        if (followerId == followeeId) {
            throw SelfFollowException("자기 자신을 팔로우할 수 없습니다.")
        }
        userRepository.findById(followerId)
            .orElseThrow { NotFoundException("팔로워 사용자를 찾을 수 없습니다: $followerId") }
        userRepository.findById(followeeId)
            .orElseThrow { NotFoundException("팔로우 대상 사용자를 찾을 수 없습니다: $followeeId") }
        if (followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw AlreadyFollowingException("이미 팔로우 중인 사용자입니다.")
        }
        val follow = FollowEntity(followerId = followerId, followeeId = followeeId)
        return followRepository.save(follow)
    }

    @Transactional
    fun unfollow(followerId: String, followeeId: String) {
        if (followerId == followeeId) {
            throw SelfFollowException("자기 자신을 언팔로우할 수 없습니다.")
        }
        if (!followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw NotFollowingException("팔로우 중이 아닌 사용자입니다.")
        }
        followRepository.deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followeeId: String): Boolean =
        followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)

    @Transactional(readOnly = true)
    fun getFollowerCount(userId: String): Long {
        userRepository.findById(userId)
            .orElseThrow { NotFoundException("사용자를 찾을 수 없습니다: $userId") }
        return followRepository.countByFolloweeId(userId)
    }

    @Transactional(readOnly = true)
    fun getFollowingCount(userId: String): Long {
        userRepository.findById(userId)
            .orElseThrow { NotFoundException("사용자를 찾을 수 없습니다: $userId") }
        return followRepository.countByFollowerId(userId)
    }
}
