@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ─────────────────────────────────────────────
    // follow()
    // ─────────────────────────────────────────────

    @Test
    fun `should follow successfully when both users exist and not yet following`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val follower = UserEntity(id = followerId, nickname = "Alice")
        val followee = UserEntity(id = followeeId, nickname = "Bob")
        val savedFollow = FollowEntity(id = "follow-1", followerId = followerId, followeeId = followeeId)

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(follower))
